export const getCompetitionWorkoutsForScoreEntryFn = createServerFn({
  method: "GET",
})
  .inputValidator((data: unknown) =>
    volunteerScoreAccessInputSchema.parse(data),
  )
  .handler(async ({ data }) => {
    // Check score access permission
    await requireScoreAccess(data.competitionTeamId)

    const db = getDb()

    // Get the competition's programming track via programmingTracksTable
    const track = await db.query.programmingTracksTable.findFirst({
      where: eq(programmingTracksTable.competitionId, data.competitionId),
    })

    if (!track) {
      return { workouts: [] }
    }

    // Get all workouts for this track
    const trackWorkouts = await db
      .select({
        id: trackWorkoutsTable.id,
        trackId: trackWorkoutsTable.trackId,
        workoutId: trackWorkoutsTable.workoutId,
        trackOrder: trackWorkoutsTable.trackOrder,
        notes: trackWorkoutsTable.notes,
        pointsMultiplier: trackWorkoutsTable.pointsMultiplier,
        parentEventId: trackWorkoutsTable.parentEventId,
        heatStatus: trackWorkoutsTable.heatStatus,
        eventStatus: trackWorkoutsTable.eventStatus,
        sponsorId: trackWorkoutsTable.sponsorId,
        createdAt: trackWorkoutsTable.createdAt,
        updatedAt: trackWorkoutsTable.updatedAt,
        workout: {
          id: workouts.id,
          name: workouts.name,
          description: workouts.description,
          scheme: workouts.scheme,
          scoreType: workouts.scoreType,
          roundsToScore: workouts.roundsToScore,
          repsPerRound: workouts.repsPerRound,
          tiebreakScheme: workouts.tiebreakScheme,
          timeCap: workouts.timeCap,
        },
      })
      .from(trackWorkoutsTable)
      .innerJoin(workouts, eq(trackWorkoutsTable.workoutId, workouts.id))
      .where(eq(trackWorkoutsTable.trackId, track.id))
      .orderBy(trackWorkoutsTable.trackOrder)

    return { workouts: trackWorkouts }
  })

/**
 * Get competition divisions for volunteers with score access
 * This is a simplified version that only requires score access entitlement
 */
export const getCompetitionDivisionsForScoreEntryFn = createServerFn({
  method: "GET",
})
  .inputValidator((data: unknown) =>
    volunteerScoreAccessInputSchema.parse(data),
  )
  .handler(async ({ data }) => {
    // Check score access permission
    await requireScoreAccess(data.competitionTeamId)

    const db = getDb()

    // Get competition settings to find the scaling group
    const [competition] = await db
      .select()
      .from(competitionsTable)
      .where(eq(competitionsTable.id, data.competitionId))
      .limit(1)

    if (!competition) {
      throw new Error("Competition not found")
    }

    // Parse settings to get scaling group ID
    let scalingGroupId: string | null = null
    if (competition.settings) {
      try {
        const settings = JSON.parse(competition.settings) as {
          divisions?: { scalingGroupId?: string }
        }
        scalingGroupId = settings?.divisions?.scalingGroupId ?? null
      } catch {
        // Ignore parse errors
      }
    }

    if (!scalingGroupId) {
      return { divisions: [] }
    }

    // Get divisions
    const divisions = await db
      .select({
        id: scalingLevelsTable.id,
        label: scalingLevelsTable.label,
        position: scalingLevelsTable.position,
      })
      .from(scalingLevelsTable)
      .where(eq(scalingLevelsTable.scalingGroupId, scalingGroupId))
      .orderBy(scalingLevelsTable.position)

    return { divisions }
  })

/**
 * Backfill: Recompute multi-round time-with-cap scores that were saved
 * with the old clamping bug (parent scoreValue clamped to timeCap).
 *
 * For each affected score:
 * - Re-aggregates parent scoreValue from the persisted rounds using the
 *   workout's scoreType.
 * - Recomputes per-round status based on encoded value vs cap.
 * - Recomputes parent status: "cap" if any round capped, else "scored".
 * - Recomputes sortKey.
 *
 * Scoped to a single competition. Requires MANAGE_COMPETITIONS.
 */
export const backfillMultiRoundCapScoresFn = createServerFn({ method: "POST" })
  .inputValidator((raw: unknown) =>
    z
      .object({
        organizingTeamId: z.string().min(1),
        competitionId: z.string().min(1),
        /** Dry-run: compute but don't write. Defaults to false. */
        dryRun: z.boolean().optional(),
      })
      .parse(raw),
  )
  .handler(async ({ data }) => {
    const db = getDb()

    const [competition] = await db
      .select({ organizingTeamId: competitionsTable.organizingTeamId })
      .from(competitionsTable)
      .where(eq(competitionsTable.id, data.competitionId))
      .limit(1)

    if (!competition) {
      throw new Error("Competition not found")
    }

    if (competition.organizingTeamId !== data.organizingTeamId) {
      throw new Error("Competition does not belong to this team")
    }

    await requireTeamPermission(
      competition.organizingTeamId,
      TEAM_PERMISSIONS.MANAGE_COMPETITIONS,
    )

    // Resolve track for this competition to scope trackWorkoutIds.
    // Competition ownership was verified above, so competitionId filter is
    // sufficient for multi-tenant isolation.
    const track = await db.query.programmingTracksTable.findFirst({
      where: eq(programmingTracksTable.competitionId, data.competitionId),
    })
    if (!track) {
      return { scanned: 0, updated: 0, skipped: 0, changes: [] }
    }

    const trackWorkoutRows = await db
      .select({
        id: trackWorkoutsTable.id,
        workoutId: trackWorkoutsTable.workoutId,
        scheme: workouts.scheme,
        scoreType: workouts.scoreType,
        timeCap: workouts.timeCap,
        tiebreakScheme: workouts.tiebreakScheme,
      })
      .from(trackWorkoutsTable)
      .innerJoin(workouts, eq(trackWorkoutsTable.workoutId, workouts.id))
      .where(
        and(
          eq(trackWorkoutsTable.trackId, track.id),
          eq(workouts.scheme, "time-with-cap"),
        ),
      )

    if (trackWorkoutRows.length === 0) {
      return { scanned: 0, updated: 0, skipped: 0, changes: [] }
    }

    const trackWorkoutIds = trackWorkoutRows.map((tw) => tw.id)
    const twById = new Map(trackWorkoutRows.map((tw) => [tw.id, tw]))

    // Load all scores for these track workouts
    const scores = await db
      .select({
        id: scoresTable.id,
        userId: scoresTable.userId,
        competitionEventId: scoresTable.competitionEventId,
        scheme: scoresTable.scheme,
        scoreType: scoresTable.scoreType,
        scoreValue: scoresTable.scoreValue,
        status: scoresTable.status,
        timeCapMs: scoresTable.timeCapMs,
        tiebreakScheme: scoresTable.tiebreakScheme,
        tiebreakValue: scoresTable.tiebreakValue,
        secondaryValue: scoresTable.secondaryValue,
        sortKey: scoresTable.sortKey,
      })
      .from(scoresTable)
      .where(inArray(scoresTable.competitionEventId, trackWorkoutIds))

    if (scores.length === 0) {
      return { scanned: 0, updated: 0, skipped: 0, changes: [] }
    }

    const scoreIds = scores.map((s) => s.id)
    const roundRows = await db
      .select({
        scoreId: scoreRoundsTable.scoreId,
        id: scoreRoundsTable.id,
        roundNumber: scoreRoundsTable.roundNumber,
        value: scoreRoundsTable.value,
        status: scoreRoundsTable.status,
      })
      .from(scoreRoundsTable)
      .where(inArray(scoreRoundsTable.scoreId, scoreIds))

    // Group rounds by scoreId
    const roundsByScore = new Map<string, typeof roundRows>()
    for (const r of roundRows) {
      const list = roundsByScore.get(r.scoreId) ?? []
      list.push(r)
      roundsByScore.set(r.scoreId, list)
    }

    const changes: Array<{
      scoreId: string
      userId: string
      trackWorkoutId: string | null
      before: { scoreValue: number | null; status: string }
      after: { scoreValue: number; status: "scored" | "cap" }
      rounds: Array<{
        roundNumber: number
        value: number
        status: "scored" | "cap"
      }>
    }> = []

    let updated = 0
    let skipped = 0

    for (const score of scores) {
      const rounds = (roundsByScore.get(score.id) ?? []).sort(
        (a, b) => a.roundNumber - b.roundNumber,
      )
      if (rounds.length < 2) {
        skipped++
        continue
      }
      const tw = score.competitionEventId
        ? twById.get(score.competitionEventId)
        : null
      if (!tw || !tw.timeCap) {
        skipped++
        continue
      }

      const capMs = tw.timeCap * 1000
      const roundValues = rounds.map((r) => r.value)
      const effectiveScoreType =
        (tw.scoreType as ScoreType) ||
        (score.scoreType as ScoreType) ||
        getDefaultScoreType("time-with-cap")

      const recomputedValue = aggregateValues(roundValues, effectiveScoreType)
      if (recomputedValue === null) {
        skipped++
        continue
      }

      const roundStatuses: Array<"scored" | "cap"> = roundValues.map((v) =>
        v >= capMs ? "cap" : "scored",
      )
      const cappedRoundCount = roundStatuses.filter((s) => s === "cap").length
      const anyCap = cappedRoundCount > 0
      const newStatus: "scored" | "cap" = anyCap ? "cap" : "scored"

      const newSortKey = computeSortKey({
        value: recomputedValue,
        status: newStatus,
        scheme: "time-with-cap",
        scoreType: effectiveScoreType,
        cappedRoundCount,
        tiebreak:
          score.tiebreakValue !== null && score.tiebreakScheme
            ? {
                scheme: score.tiebreakScheme as "time" | "reps",
                value: score.tiebreakValue,
              }
            : undefined,
      })
      const newSortKeyString = sortKeyToString(newSortKey)

      // Only update when something actually changed. A stale `sortKey` is
      // on its own sufficient reason to rewrite — this is how the backfill
      // repairs scores written before the cap-count tiebreaker was added.
      const valueChanged = score.scoreValue !== recomputedValue
      const statusChanged = score.status !== newStatus
      const roundStatusChanged = rounds.some(
        (r, i) => (r.status ?? null) !== roundStatuses[i],
      )
      const sortKeyChanged = score.sortKey !== newSortKeyString

      if (
        !valueChanged &&
        !statusChanged &&
        !roundStatusChanged &&
        !sortKeyChanged
      ) {
        skipped++
        continue
      }

      changes.push({
        scoreId: score.id,
        userId: score.userId,
        trackWorkoutId: score.competitionEventId,
        before: { scoreValue: score.scoreValue, status: score.status },
        after: { scoreValue: recomputedValue, status: newStatus },
        rounds: rounds.map((r, i) => ({
          roundNumber: r.roundNumber,
          value: r.value,
          status: roundStatuses[i],
        })),
      })

      if (!data.dryRun) {
        await db.transaction(async (tx) => {
          await tx
            .update(scoresTable)
            .set({
              scoreValue: recomputedValue,
              status: newStatus,
              statusOrder: STATUS_ORDER[newStatus],
              sortKey: newSortKeyString,
              updatedAt: new Date(),
            })
            .where(eq(scoresTable.id, score.id))

          for (let i = 0; i < rounds.length; i++) {
            const round = rounds[i]
            const desired = roundStatuses[i]
            if ((round.status ?? null) !== desired) {
              await tx
                .update(scoreRoundsTable)
                .set({ status: desired })
                .where(eq(scoreRoundsTable.id, round.id))
            }
          }
        })
      }

      updated++
    }

    logInfo({
      message: "[Score] Multi-round cap backfill completed",
      attributes: {
        competitionId: data.competitionId,
        scanned: scores.length,
        updated,
        skipped,
        dryRun: !!data.dryRun,
      },
    })

    return {
      scanned: scores.length,
      updated,
      skipped,
      dryRun: !!data.dryRun,
      changes,
    }
  })

import { Card, CardContent } from "@/components/ui/card"
import { EventSubmissionCard } from "./event-submission-card"
import type {
  AthleteDetailEvent,
  AthleteDetailScore,
  AthleteDetailVideoSubmission,
} from "./types"

interface VideoSubmissionsSectionProps {
  registrationId: string
  competitionId: string
  organizingTeamId: string
  divisionId: string | null
  events: AthleteDetailEvent[]
  videoSubmissions: AthleteDetailVideoSubmission[]
  scores: AthleteDetailScore[]
  teamSize: number
  captainUserId: string
  formatDateTime: (d: Date | string | null | undefined) => string
}

export function VideoSubmissionsSection({
  registrationId,
  competitionId,
  organizingTeamId,
  divisionId,
  events,
  videoSubmissions,
  scores,
  teamSize,
  captainUserId,
  formatDateTime,
}: VideoSubmissionsSectionProps) {
  if (events.length === 0) {
    return (
      <Card>
        <CardContent className="py-10 text-center text-sm text-muted-foreground">
          No events configured for this competition yet.
        </CardContent>
      </Card>
    )
  }

  return (
    <div className="space-y-4">
      {events.map((event) => (
        <EventSubmissionCard
          key={event.id}
          event={event}
          registrationId={registrationId}
          competitionId={competitionId}
          organizingTeamId={organizingTeamId}
          divisionId={divisionId}
          submissions={videoSubmissions.filter(
            (s) => s.trackWorkoutId === event.trackWorkoutId,
          )}
          scores={scores.filter(
            (s) => s.trackWorkoutId === event.trackWorkoutId,
          )}
          teamSize={teamSize}
          captainUserId={captainUserId}
          formatDateTime={formatDateTime}
        />
      ))}
    </div>
  )
}

              totalCents: true,
              status: true,
              completedAt: true,
              stripePaymentIntentId: true,
            },
          })
        : Promise.resolve(null),
    ])

    const relevantScores = scoresRows as (typeof scoresTable.$inferSelect)[]

    // Load rounds for relevant scores in one query
    const scoreIds = relevantScores.map((s) => s.id)
    const scoreRoundsRows =
      scoreIds.length > 0
        ? await db
            .select({
              scoreId: scoreRoundsTable.scoreId,
              roundNumber: scoreRoundsTable.roundNumber,
              value: scoreRoundsTable.value,
            })
            .from(scoreRoundsTable)
            .where(inArray(scoreRoundsTable.scoreId, scoreIds))
            .orderBy(asc(scoreRoundsTable.roundNumber))
        : []

    const roundsByScoreId = new Map<
      string,
      { roundIndex: number; scoreValue: number }[]
    >()
    for (const r of scoreRoundsRows) {
      const list = roundsByScoreId.get(r.scoreId) ?? []
      list.push({ roundIndex: r.roundNumber, scoreValue: r.value })
      roundsByScoreId.set(r.scoreId, list)
    }

    // Shape answers keyed by `${userId}:${questionId}`
    const answers: Record<string, string> = {}
    for (const a of answersRows) {
      answers[`${a.userId}:${a.questionId}`] = a.answer
    }

    // Shape pending invites
    const pendingInvites = pendingInvitesRows.map((inv) => {
      let pendingAnswers:
        | Array<{ questionId: string; answer: string }>
        | undefined
      let pendingSignatures:
        | Array<{ waiverId: string; signedAt: string; signatureName: string }>
        | undefined
      let submittedAt: string | undefined
      let guestName: string | undefined
      let affiliateName: string | undefined
      if (inv.metadata) {
        try {
          const meta = JSON.parse(inv.metadata) as Record<string, unknown>
          if (Array.isArray(meta.pendingAnswers)) {
            pendingAnswers = meta.pendingAnswers as typeof pendingAnswers
          }
          if (Array.isArray(meta.pendingSignatures)) {
            pendingSignatures =
              meta.pendingSignatures as typeof pendingSignatures
          }
          if (typeof meta.submittedAt === "string") {
            submittedAt = meta.submittedAt
          }
          if (typeof meta.guestName === "string") {
            guestName = meta.guestName
          }
          if (typeof meta.affiliateName === "string") {
            affiliateName = meta.affiliateName
          }
        } catch {
          // ignore invalid JSON
        }
      }
      return {
        id: inv.id,
        email: inv.email,
        status: inv.status,
        guestName,
        createdAt: inv.createdAt,
        expiresAt: inv.expiresAt,
        pendingAnswers,
        pendingSignatures,
        submittedAt,
        affiliateName,
      }
    })

    const captain = Array.isArray(registration.captain)
      ? registration.captain[0]
      : registration.captain

    const division = Array.isArray(registration.division)
      ? registration.division[0]
      : registration.division

    return {
      registration: {
        id: registration.id,
        status: registration.status,
        teamName: registration.teamName,
        divisionId: registration.divisionId,
        paymentStatus: registration.paymentStatus,
        paidAt: registration.paidAt,
        registeredAt: registration.registeredAt,
        metadata: registration.metadata,
        commercePurchaseId: registration.commercePurchaseId,
        userId: registration.userId,
        athleteTeamId: registration.athleteTeamId,
      },
      competition: {
        id: competition.id,
        name: competition.name,
        organizingTeamId: competition.organizingTeamId,
        competitionType: competition.competitionType,
        startDate: competition.startDate,
        endDate: competition.endDate,
      },
      division: division
        ? {
            id: division.id,
            label: division.label,
            teamSize: division.teamSize,
          }
        : null,
      captain: captain ?? null,
      athleteTeam: athleteTeam
        ? {
            id: athleteTeam.id,
            name: athleteTeam.name,
            memberships: (
              (athleteTeam.memberships ?? []) as Array<{
                id: string
                userId: string
                joinedAt: Date | null
                isActive: boolean
                roleId: string
                user:
                  | {
                      id: string
                      firstName: string | null
                      lastName: string | null
                      email: string
                      avatar: string | null
                    }
                  | null
                  | Array<{
                      id: string
                      firstName: string | null
                      lastName: string | null
                      email: string
                      avatar: string | null
                    }>
              }>
            ).map((m) => ({
              id: m.id,
              userId: m.userId,
              joinedAt: m.joinedAt,
              isActive: m.isActive,
              role: m.roleId,
              user: Array.isArray(m.user) ? m.user[0] : m.user,
            })),
          }
        : null,
      pendingInvites,
      questions,
      answers,
      waivers,
      waiverSignatures: waiverSignaturesRows,
      events: visibleCompetitionEvents.map((e) => ({
        id: e.id,
        trackWorkoutId: e.trackWorkoutId,
        workoutId: e.workoutId,
        workoutName: e.workoutName,
        scheme: e.scheme,
        scoreType: e.scoreType,
        timeCap: e.timeCap,
        tiebreakScheme: e.tiebreakScheme,
        repsPerRound: e.repsPerRound,
        roundsToScore: e.roundsToScore,
        submissionWindowStartsAt: e.submissionOpensAt,
        submissionWindowEndsAt: e.submissionClosesAt,
        ordinal: e.ordinal,
      })),
      videoSubmissions: videoSubmissionsRows.map((v) => ({
        id: v.id,
        eventId: v.trackWorkoutId, // keyed by trackWorkoutId in this system
        trackWorkoutId: v.trackWorkoutId,
        videoIndex: v.videoIndex,
        userId: v.userId,
        videoUrl: v.videoUrl,
        notes: v.notes,
        reviewedAt: v.reviewedAt,
        status: v.reviewStatus,
        scoreId:
          relevantScores.find(
            (s) =>
              s.competitionEventId === v.trackWorkoutId &&
              s.userId === v.userId,
          )?.id ?? null,
      })),
      scores: relevantScores.map((s) => ({
        id: s.id,
        trackWorkoutId: s.competitionEventId,
        userId: s.userId,
        divisionId: s.scalingLevelId,
        scoreStatus: s.status,
        scoreValue: s.scoreValue,
        secondaryScore: s.secondaryValue,
        tieBreakScore: s.tiebreakValue,
        scoreRounds: roundsByScoreId.get(s.id) ?? [],
        updatedAt: s.updatedAt,
      })),
      commercePurchase: commercePurchase ?? null,
    }
  })

// ============================================================================

import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { useState } from "react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import type { ParseResult, WorkoutScheme } from "@/lib/scoring"
import { parseScore } from "@/lib/scoring"
import { cn } from "@/lib/utils"
import {
  enterSubmissionScoreFn,
  type EventDetails,
} from "@/server-fns/submission-verification-fns"
import {
  getSchemeLabel,
  getScoreHelpText,
  getScorePlaceholder,
} from "./score-entry-helpers"

interface EnterScoreFormProps {
  videoSubmissionId: string
  competitionId: string
  trackWorkoutId: string
  event: EventDetails
}

/**
 * First-time score entry for video submissions whose athlete uploaded a
 * video without filling in the score field. Renders in the no-score branch
 * of both the organizer and volunteer review surfaces; once submitted, the
 * route invalidates and the standard `VerificationControls` takes over.
 *
 * Mirrors the score-entry UX of `video-submission-form.tsx` — schema-aware
 * parsing, auto-derived cap status for time-with-cap, tiebreak input — so
 * reviewers enter scores through the same validation path as athletes.
 */
export function EnterScoreForm({
  videoSubmissionId,
  competitionId,
  trackWorkoutId,
  event,
}: EnterScoreFormProps) {
  const router = useRouter()
  const enterFn = useServerFn(enterSubmissionScoreFn)

  const scheme = event.workout.scheme as WorkoutScheme
  const roundsToScore = Math.max(1, event.workout.roundsToScore ?? 1)
  const isMultiRound = roundsToScore > 1
  const timeCap = event.workout.timeCap
  const tiebreakScheme = event.workout.tiebreakScheme as WorkoutScheme | null

  const [scoreInput, setScoreInput] = useState("")
  const [roundScoreInputs, setRoundScoreInputs] = useState<string[]>(() =>
    Array.from({ length: roundsToScore }, () => ""),
  )
  const [secondaryScore, setSecondaryScore] = useState("")
  const [tiebreakInput, setTiebreakInput] = useState("")
  const [reviewerNotes, setReviewerNotes] = useState("")
  const [noRepCount, setNoRepCount] = useState("")
  const [error, setError] = useState<string | null>(null)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [hasAttemptedSubmit, setHasAttemptedSubmit] = useState(false)

  const parseResult: ParseResult | null =
    !isMultiRound && scoreInput.trim()
      ? parseScore(scoreInput, scheme)
      : null

  const roundParseResults: (ParseResult | null)[] = isMultiRound
    ? roundScoreInputs.map((s) => (s.trim() ? parseScore(s, scheme) : null))
    : []

  const tiebreakParseResult: ParseResult | null =
    tiebreakScheme && tiebreakInput.trim()
      ? parseScore(tiebreakInput, tiebreakScheme)
      : null

  // Auto-derive cap status from parsed time vs the workout's time cap —
  // mirrors video-submission-form.tsx so reviewers don't need a separate
  // status picker.
  const scoreStatus: "scored" | "cap" = (() => {
    if (
      parseResult?.isValid &&
      parseResult.encoded !== null &&
      scheme === "time-with-cap" &&
      timeCap
    ) {
      const capMs = timeCap * 1000
      if (parseResult.encoded >= capMs) return "cap"
    }
    return "scored"
  })()

  const showSecondaryInput =
    !isMultiRound && scheme === "time-with-cap" && scoreStatus === "cap"

  const canSubmit = isMultiRound
    ? roundScoreInputs.every((s) => s.trim().length > 0)
    : scoreInput.trim().length > 0

  async function handleSubmit() {
    setError(null)
    setHasAttemptedSubmit(true)

    if (isMultiRound) {
      for (let i = 0; i < roundScoreInputs.length; i++) {
        const input = roundScoreInputs[i]
        if (!input.trim()) {
          setError(`Please enter a score for round ${i + 1}`)
          return
        }
        const r = parseScore(input, scheme)
        if (!r.isValid) {
          setError(`Round ${i + 1}: ${r.error ?? "invalid score"}`)
          return
        }
      }
    } else {
      if (!scoreInput.trim()) {
        setError("Please enter a score")
        return
      }
      if (!parseResult?.isValid) {
        setError(parseResult?.error ?? "Invalid score")
        return
      }
    }

    if (tiebreakScheme && tiebreakInput.trim() && !tiebreakParseResult?.isValid) {
      setError(tiebreakParseResult?.error ?? "Invalid tiebreak")
      return
    }

    setIsSubmitting(true)
    try {
      if (isMultiRound) {
        await enterFn({
          data: {
            competitionId,
            trackWorkoutId,
            videoSubmissionId,
            roundScores: roundScoreInputs.map((s, i) => ({
              roundNumber: i + 1,
              score: s.trim(),
            })),
            tieBreakScore: tiebreakInput.trim() || undefined,
            reviewerNotes: reviewerNotes.trim() || undefined,
            noRepCount: noRepCount
              ? Number.parseInt(noRepCount, 10)
              : undefined,
          },
        })
      } else {
        await enterFn({
          data: {
            competitionId,
            trackWorkoutId,
            videoSubmissionId,
            score: scoreInput.trim(),
            scoreStatus,
            secondaryScore:
              scoreStatus === "cap"
                ? secondaryScore.trim() || undefined
                : undefined,
            tieBreakScore: tiebreakInput.trim() || undefined,
            reviewerNotes: reviewerNotes.trim() || undefined,
            noRepCount: noRepCount
              ? Number.parseInt(noRepCount, 10)
              : undefined,
          },
        })
      }
      await router.invalidate()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to enter score")
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Enter Score</CardTitle>
        <CardDescription>
          The athlete uploaded a video without filling in the score field.
          Watch the video and enter what they actually scored — this creates
          the missing scores row and marks the submission reviewed.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {error && (
          <div className="rounded-md border border-destructive/50 bg-destructive/10 p-2 text-sm text-destructive">
            {error}
          </div>
        )}

        {isMultiRound ? (
          <div className="space-y-3">
            <Label>{getSchemeLabel(scheme)} per Round</Label>
            {roundScoreInputs.map((input, i) => {
              const roundResult = roundParseResults[i]
              return (
                <div key={`enter-r-${i + 1}`} className="space-y-1">
                  <Label
                    htmlFor={`enter-round-${i}`}
                    className="text-sm font-normal text-muted-foreground"
                  >
                    Round {i + 1}
                  </Label>
                  <Input
                    id={`enter-round-${i}`}
                    value={input}
                    onChange={(e) => {
                      const next = [...roundScoreInputs]
                      next[i] = e.target.value
                      setRoundScoreInputs(next)
                    }}
                    placeholder={getScorePlaceholder(scheme)}
                    className={cn(
                      "font-mono",
                      ((roundResult?.error && !roundResult?.isValid) ||
                        (hasAttemptedSubmit && !input.trim())) &&
                        "border-destructive",
                    )}
                    disabled={isSubmitting}
                  />
                  {roundResult?.isValid && (
                    <p className="text-xs text-green-600 dark:text-green-400">
                      Parsed as: {roundResult.formatted}
                    </p>
                  )}
                  {roundResult?.error && (
                    <p className="text-xs text-destructive">
                      {roundResult.error}
                    </p>
                  )}
                </div>
              )
            })}
            {getScoreHelpText(scheme, timeCap) && (
              <p className="text-xs text-muted-foreground">
                {getScoreHelpText(scheme, timeCap)}
              </p>
            )}
            {scheme === "time-with-cap" && timeCap ? (
              <p className="text-[11px] text-muted-foreground">
                Status is derived per round from the time vs the per-round cap.
              </p>
            ) : null}
          </div>
        ) : (
          <div className="space-y-2">
            <Label htmlFor="enter-score">{getSchemeLabel(scheme)}</Label>
            <Input
              id="enter-score"
              value={scoreInput}
              onChange={(e) => setScoreInput(e.target.value)}
              placeholder={getScorePlaceholder(scheme)}
              className={cn(
                "font-mono",
                ((parseResult?.error && !parseResult?.isValid) ||
                  (hasAttemptedSubmit && !scoreInput.trim())) &&
                  "border-destructive",
              )}
              disabled={isSubmitting}
            />
            {getScoreHelpText(scheme, timeCap) && (
              <p className="text-xs text-muted-foreground">
                {getScoreHelpText(scheme, timeCap)}
              </p>
            )}
            {parseResult?.isValid && (
              <p className="text-xs text-green-600 dark:text-green-400">
                Parsed as: {parseResult.formatted}
                {scoreStatus === "cap" && " (Time Cap)"}
              </p>
            )}
            {parseResult?.error && (
              <p className="text-xs text-destructive">{parseResult.error}</p>
            )}
          </div>
        )}

        {!isMultiRound && scoreStatus === "cap" && (
          <p className="text-xs text-amber-600 dark:text-amber-400">
            Time cap hit. Enter the reps completed at the cap below.
          </p>
        )}
        {showSecondaryInput && (
          <div className="space-y-2">
            <Label htmlFor="enter-secondary">Reps Completed at Cap</Label>
            <Input
              id="enter-secondary"
              type="number"
              value={secondaryScore}
              onChange={(e) => setSecondaryScore(e.target.value)}
              placeholder="e.g., 150"
              min="0"
              disabled={isSubmitting}
            />
            <p className="text-xs text-muted-foreground">
              Total reps/work completed when the time cap hit
            </p>
          </div>
        )}

        {tiebreakScheme && (
          <div className="space-y-2">
            <Label htmlFor="enter-tiebreak">
              Tiebreak ({tiebreakScheme === "time" ? "Time" : "Reps/Weight"})
            </Label>
            <Input
              id="enter-tiebreak"
              value={tiebreakInput}
              onChange={(e) => setTiebreakInput(e.target.value)}
              placeholder={
                tiebreakScheme === "time" ? "e.g., 3:45" : "e.g., 100"
              }
              className={cn(
                "font-mono",
                tiebreakParseResult?.error &&
                  !tiebreakParseResult?.isValid &&
                  "border-destructive",
              )}
              disabled={isSubmitting}
            />
            {tiebreakParseResult?.isValid && (
              <p className="text-xs text-green-600 dark:text-green-400">
                Parsed as: {tiebreakParseResult.formatted}
              </p>
            )}
            {tiebreakParseResult?.error && (
              <p className="text-xs text-destructive">
                {tiebreakParseResult.error}
              </p>
            )}
            <p className="text-xs text-muted-foreground">
              {tiebreakScheme === "time"
                ? "Time to complete specified reps/work"
                : "Reps or weight completed for tiebreak"}
            </p>
          </div>
        )}

        <div className="space-y-2">
          <Label htmlFor="enter-no-rep" className="text-xs">
            No-rep count (optional)
          </Label>
          <Input
            id="enter-no-rep"
            value={noRepCount}
            onChange={(e) => setNoRepCount(e.target.value)}
            placeholder="e.g. 12"
            type="number"
            min="0"
            className="font-mono"
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="enter-notes" className="text-xs">
            Note to athlete (optional)
          </Label>
          <Textarea
            id="enter-notes"
            value={reviewerNotes}
            onChange={(e) => setReviewerNotes(e.target.value)}
            placeholder="Why this score was entered..."
            rows={2}
            className="text-sm"
          />
        </div>

        <Button
          className="w-full"
          onClick={handleSubmit}
          disabled={!canSubmit || isSubmitting}
        >
          {isSubmitting ? "Saving..." : "Save Score"}
        </Button>
      </CardContent>
    </Card>
  )
}

